import api from './api';

export const authService = {
  login: async (username, password) => {
    try {
      const response = await api.post('/auth/login', { username, password });
      console.log('Login API response:', response.data);
      
      if (response.data.token) {
        localStorage.setItem('token', response.data.token);
        localStorage.setItem('user', JSON.stringify(response.data));
      }
      return response.data;
    } catch (error) {
      console.error('Login API error:', error);
      throw error;
    }
  },

  logout: () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
  },

  getCurrentUser: () => {
    try {
      const userStr = localStorage.getItem('user');
      if (userStr) {
        const user = JSON.parse(userStr);
        // Ensure roles is an array
        if (!user.roles) {
          user.roles = user.authorities || [];
        }
        return user;
      }
      return null;
    } catch (error) {
      console.error('Error parsing user data:', error);
      return null;
    }
  },

  getToken: () => {
    return localStorage.getItem('token');
  },

  isAuthenticated: () => {
    const token = localStorage.getItem('token');
    return !!token;
  },

  register: async (username, password) => {
    try {
      const response = await api.post('/auth/register', { username, password });
      return response.data;
    } catch (error) {
      console.error('Registration error:', error);
      throw error;
    }
  },

  resetPassword: async () => {
    try {
      const response = await api.post('/auth/reset-password');
      return response.data;
    } catch (error) {
      console.error('Reset password error:', error);
      throw error;
    }
  },

  checkUser: async () => {
    try {
      const response = await api.get('/auth/check-user');
      return response.data;
    } catch (error) {
      console.error('Check user error:', error);
      throw error;
    }
  },

  // ⭐ Check if user has a specific role
  hasRole: (roleName) => {
    const user = authService.getCurrentUser();
    if (!user) return false;
    const roles = user.roles || user.authorities || [];
    return roles.some(role => role.name === roleName || role === roleName);
  },

  // ⭐ Check if user is admin
  isAdmin: () => {
    return authService.hasRole('ROLE_ADMIN');
  },

  // ⭐ Check if user has any of the given roles
  hasAnyRole: (roleNames) => {
    const user = authService.getCurrentUser();
    if (!user) return false;
    const roles = user.roles || user.authorities || [];
    return roleNames.some(roleName => 
      roles.some(role => role.name === roleName || role === roleName)
    );
  }
};

export default authService;
